	@Test
	void adaptiveSetPromotesToPartitionedRoaringAndClearsForReuse() {
		String previousEnabled = System.getProperty(LmdbIdSets.ROARING_ENABLED_PROPERTY);
		String previousMinIds = System.getProperty(LmdbIdSets.ROARING_MIN_IDS_PROPERTY);
		System.setProperty(LmdbIdSets.ROARING_ENABLED_PROPERTY, "true");
		System.setProperty(LmdbIdSets.ROARING_MIN_IDS_PROPERTY, "4");
		try {
			LmdbIdSet set = LmdbIdSets.create(1);

			long lowId = 42L;
			long highId = (3L << 33) | 17L;
			assertThat(set.add(lowId)).isTrue();
			assertThat(set.add(highId)).isTrue();
			assertThat(set.add(lowId)).isFalse();
			assertThat(set.size()).isEqualTo(2);

			for (int i = 0; i < 8; i++) {
				assertThat(set.add((7L << 33) | i)).isTrue();
			}

			assertThat(set.implementationName()).contains("roaring");
			assertThat(set.contains(lowId)).isTrue();
			assertThat(set.contains(highId)).isTrue();
			assertThat(set.contains((7L << 33) | 6L)).isTrue();
			assertThat(set.contains((9L << 33) | 6L)).isFalse();
			assertThat(set.size()).isEqualTo(10);

			set.clear();

			assertThat(set.size()).isZero();
			assertThat(set.contains(lowId)).isFalse();
			assertThat(set.add((11L << 33) | 5L)).isTrue();
			assertThat(set.contains((11L << 33) | 5L)).isTrue();
			assertThat(set.size()).isEqualTo(1);
		} finally {
			restore(LmdbIdSets.ROARING_ENABLED_PROPERTY, previousEnabled);
			restore(LmdbIdSets.ROARING_MIN_IDS_PROPERTY, previousMinIds);
		}
	}

